class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.canvas = document.createElement('canvas');
        this.ctx = this.canvas.getContext('2d');
        this.container.appendChild(this.canvas);
        this.resize();
        window.addEventListener('resize', () => this.resize());
    }

    resize() {
        this.canvas.width = this.container.clientWidth;
        this.canvas.height = this.container.clientHeight;
    }

    getSteps(inputs) {
        return [
            {
                title: "The Quantum Source",
                description: "A coherent source emits particles (like photons or electrons) with a wavelength of **" + inputs.wavelength + " nm**. In quantum mechanics, these particles are described by a wave function $\\Psi$."
            },
            {
                title: "The Double Slit Barrier",
                description: "The wave function encounters a barrier with two slits separated by **" + inputs.slitSeparation + " μm**. According to Huygens' Principle, each slit acts as a new source of spherical waves."
            },
            {
                title: "Wave Superposition",
                description: "The waves from both slits overlap. The total wave function is the sum: $\\Psi_{total} = \\psi_1 + \\psi_2$. This leads to regions of constructive and destructive interference."
            },
            {
                title: "Probability Distribution",
                description: "The intensity of the pattern on the screen is proportional to the square of the amplitude: $I \\propto |\\Psi|^2$. This curve represents the probability of a particle landing at a specific point."
            },
            {
                title: "Quantum Collapse",
                description: "When we detect **" + inputs.particleCount + "** particles, they appear as individual dots. Over time, the stochastic 'hits' reconstruct the interference pattern predicted by wave theory."
            }
        ];
    }

    calculateIntensity(y, inputs, height) {
        const L = 1000; // Distance to screen (arbitrary units)
        const d = inputs.slitSeparation * 100;
        const a = inputs.slitWidth * 100;
        const lambda = inputs.wavelength / 5;

        const theta = Math.atan((y - height / 2) / L);
        const sinTheta = Math.sin(theta);

        const beta = (Math.PI * d * sinTheta) / lambda;
        const alpha = (Math.PI * a * sinTheta) / lambda;

        const interference = Math.pow(Math.cos(beta), 2);
        const diffraction = alpha === 0 ? 1 : Math.pow(Math.sin(alpha) / alpha, 2);

        return interference * diffraction;
    }

    render(inputs, stepIndex) {
        const { ctx, canvas } = this;
        const { width, height } = canvas;
        ctx.clearRect(0, 0, width, height);

        const margin = 50;
        const sourceX = 50;
        const barrierX = width * 0.3;
        const screenX = width * 0.85;
        const centerY = height / 2;

        // Background
        ctx.fillStyle = '#0f172a';
        ctx.fillRect(0, 0, width, height);

        // 1. Draw Source (Step 0+)
        ctx.beginPath();
        ctx.arc(sourceX, centerY, 10, 0, Math.PI * 2);
        ctx.fillStyle = '#3b82f6';
        ctx.fill();
        ctx.shadowBlur = 15;
        ctx.shadowColor = '#3b82f6';

        // 2. Draw Barrier (Step 1+)
        if (stepIndex >= 1) {
            ctx.shadowBlur = 0;
            ctx.strokeStyle = '#94a3b8';
            ctx.lineWidth = 4;
            const gap = inputs.slitSeparation * 10;
            ctx.beginPath();
            ctx.moveTo(barrierX, 0);
            ctx.lineTo(barrierX, centerY - gap/2 - 10);
            ctx.moveTo(barrierX, centerY - gap/2 + 10);
            ctx.lineTo(barrierX, centerY + gap/2 - 10);
            ctx.moveTo(barrierX, centerY + gap/2 + 10);
            ctx.lineTo(barrierX, height);
            ctx.stroke();
        }

        // 3. Draw Waves (Step 0, 2, 3)
        if (stepIndex === 0 || stepIndex === 2 || stepIndex === 3) {
            ctx.lineWidth = 1;
            const waveColor = `hsla(${inputs.wavelength - 300}, 100%, 50%, 0.3)`;
            ctx.strokeStyle = waveColor;

            if (stepIndex === 0) {
                for (let r = 20; r < barrierX - sourceX; r += 20) {
                    ctx.beginPath();
                    ctx.arc(sourceX, centerY, r, -Math.PI/3, Math.PI/3);
                    ctx.stroke();
                }
            } else {
                const gap = inputs.slitSeparation * 10;
                const slits = [centerY - gap/2, centerY + gap/2];
                slits.forEach(sy => {
                    for (let r = 10; r < screenX - barrierX; r += 15) {
                        ctx.beginPath();
                        ctx.arc(barrierX, sy, r, -Math.PI/2, Math.PI/2);
                        ctx.stroke();
                    }
                });
            }
        }

        // 4. Draw Intensity Graph (Step 3, 4)
        if (stepIndex >= 3) {
            ctx.beginPath();
            ctx.strokeStyle = '#4ade80';
            ctx.lineWidth = 2;
            for (let y = 0; y < height; y++) {
                const intensity = this.calculateIntensity(y, inputs, height);
                const xPos = screenX + (intensity * 80);
                if (y === 0) ctx.moveTo(xPos, y);
                else ctx.lineTo(xPos, y);
            }
            ctx.stroke();

            // Screen line
            ctx.strokeStyle = '#ffffff';
            ctx.beginPath();
            ctx.moveTo(screenX, 0);
            ctx.lineTo(screenX, height);
            ctx.stroke();
        }

        // 5. Draw Particles (Step 4)
        if (stepIndex === 4) {
            const count = inputs.particleCount;
            ctx.fillStyle = '#fbbf24';
            // Use a fixed seed for deterministic randomness during re-renders
            let seed = 123;
            const pseudoRandom = () => {
                seed = (seed * 9301 + 49297) % 233280;
                return seed / 233280;
            };

            for (let i = 0; i < count; i++) {
                const y = pseudoRandom() * height;
                const prob = this.calculateIntensity(y, inputs, height);
                if (pseudoRandom() < prob) {
                    ctx.beginPath();
                    ctx.arc(screenX - 2 - pseudoRandom() * 5, y, 1.5, 0, Math.PI * 2);
                    ctx.fill();
                }
            }
        }
    }
}
